
CREATE  VIEW `vue_versement_achat`  AS SELECT `ac`.`fournisseur_id` AS `fournisseur_id`, `ac`.`code_achat` AS `code_achat`, `ac`.`entrepot_id` AS `entrepot_id`, `ac`.`created_at` AS `created_at`, `ac`.`date_echeance` AS `date_echeance`, coalesce(sum(`vs`.`montant_versement`),0) AS `montant_total` FROM (`versement` `vs` join `achat` `ac` on(((`ac`.`code_achat` = `vs`.`transaction_code`) and (`ac`.`statut_achat` in ('valide','encaisse'))))) WHERE ((`vs`.`type_versement` = 'achat') AND (`vs`.`etat_versement` = 1)) GROUP BY `ac`.`code_achat` ;

CREATE  VIEW `vue_versement_vente`  AS SELECT `ve`.`client_id` AS `client_id`, `ve`.`code_vente` AS `code_vente`, `ve`.`entrepot_id` AS `entrepot_id`, `ve`.`created_at` AS `created_at`, `ve`.`date_echeance` AS `date_echeance`, coalesce(sum(`vs`.`montant_versement`),0) AS `montant_total` FROM (`versement` `vs` join `vente` `ve` on(((`ve`.`code_vente` = `vs`.`transaction_code`) and (`ve`.`statut_vente` in ('valide','encaisse'))))) WHERE ((`vs`.`type_versement` = 'vente') AND (`vs`.`etat_versement` = 1)) GROUP BY `ve`.`code_vente` ;

CREATE  VIEW `vue_tresorerie_par_entrepot`  AS SELECT `t`.`entrepot_id` AS `entrepot_id`, sum(`t`.`entree`) AS `total_entree`, sum(`t`.`sortie_achat`) AS `total_sortie_achat`, sum(`t`.`depense`) AS `total_depense`, ((sum(`t`.`entree`) - sum(`t`.`sortie_achat`)) - sum(`t`.`depense`)) AS `solde_tresorerie` FROM (select `ve`.`entrepot_id` AS `entrepot_id`,`v`.`montant_versement` AS `entree`,0 AS `sortie_achat`,0 AS `depense` from (`versement` `v` join `vente` `ve` on((`ve`.`code_vente` = `v`.`transaction_code`))) where ((`v`.`type_versement` = 'vente') and (`v`.`etat_versement` = 1)) union all select `ac`.`entrepot_id` AS `entrepot_id`,0 AS `0`,`v`.`montant_versement` AS `montant_versement`,0 AS `0` from (`versement` `v` join `achat` `ac` on((`ac`.`code_achat` = `v`.`transaction_code`))) where ((`v`.`type_versement` = 'achat') and (`v`.`etat_versement` = 1)) union all select `d`.`entrepot_id` AS `entrepot_id`,0 AS `0`,0 AS `0`,`d`.`montant` AS `montant` from `depense` `d` where (`d`.`statut_depense` = 'approuve')) AS `t` GROUP BY `t`.`entrepot_id` ;



CREATE  VIEW `vue_montant_ventes`  AS SELECT `v`.`ID_vente` AS `vente_id`, `v`.`code_vente` AS `code_vente`, `v`.`client_id` AS `client_id`, `v`.`employe_id` AS `employe_id`, `v`.`etat_vente` AS `etat_vente`, `v`.`statut_vente` AS `statut_vente`, `v`.`pay_mode` AS `pay_mode`, `v`.`entrepot_id` AS `entrepot_id`, `v`.`created_at` AS `created_at`, `v`.`date_echeance` AS `date_echeance`, `v`.`updated_at` AS `updated_at`, `ent`.`libelle_entrepot` AS `libelle_entrepot`, concat(`c`.`nom_client`,' ',`c`.`prenom_client`) AS `nom_client`, coalesce(sum((`lv`.`qte` * `lv`.`prix_vente`)),0) AS `montant_total` FROM (((`vente` `v` join `sortie` `lv` on((`v`.`code_vente` = `lv`.`vente_id`))) join `client` `c` on((`v`.`client_id` = `c`.`ID_client`))) join `entrepot` `ent` on((`v`.`entrepot_id` = `ent`.`ID_entrepot`))) GROUP BY `lv`.`vente_id` ;

CREATE  VIEW `vue_montant_achats`  AS SELECT `ac`.`ID_achat` AS `achat_id`, `ac`.`code_achat` AS `code_achat`, `ac`.`employe_id` AS `employe_id`, `ac`.`fournisseur_id` AS `fournisseur_id`, `ac`.`etat_achat` AS `etat_achat`, `ac`.`pay_mode` AS `pay_mode`, `ac`.`entrepot_id` AS `entrepot_id`, `ac`.`statut_achat` AS `statut_achat`, `ac`.`created_at` AS `created_at`, `ac`.`date_echeance` AS `date_echeance`, `ent`.`libelle_entrepot` AS `libelle_entrepot`, `fn`.`nom_fournisseur` AS `nom_fournisseur`, coalesce(sum((`la`.`qte` * `la`.`prix_achat`)),0) AS `montant_total` FROM (((`achat` `ac` join `entree` `la` on((`ac`.`code_achat` = `la`.`achat_id`))) join `fournisseur` `fn` on((`ac`.`fournisseur_id` = `fn`.`ID_fournisseur`))) join `entrepot` `ent` on((`ac`.`entrepot_id` = `ent`.`ID_entrepot`))) GROUP BY `la`.`achat_id` ;



CREATE  VIEW `vue_etat_paiements`  AS SELECT coalesce(`ver`.`type_versement`,'vente') AS `nature`, `v`.`entrepot_id` AS `entrepot`, `v`.`code_vente` AS `code_transaction`, ifnull(`ver`.`pay_mode`,'...') AS `pay_mode`, `v`.`created_at` AS `date_facture`, `v`.`statut_vente` AS `statut_commande`, `vmt`.`montant_total` AS `montant_facture`, coalesce(sum(`ver`.`montant_versement`),0) AS `total_paye`, (`vmt`.`montant_total` - coalesce(sum(`ver`.`montant_versement`),0)) AS `reste_a_payer`, (case when (coalesce(sum(`ver`.`montant_versement`),0) <= 0) then 'Non payé' when (coalesce(sum(`ver`.`montant_versement`),0) < `vmt`.`montant_total`) then 'Partiel' else 'Soldé' end) AS `statut_paiement` FROM (((`vente` `v` join `vue_montant_ventes` `vmt` on((`vmt`.`code_vente` = `v`.`code_vente`))) join `sortie` `so` on((`so`.`vente_id` = `v`.`code_vente`))) left join `versement` `ver` on(((`v`.`code_vente` = `ver`.`transaction_code`) and (`ver`.`type_versement` = 'vente') and (`ver`.`etat_versement` = 1)))) WHERE (`v`.`statut_vente` in ('valide','encaisse')) GROUP BY `v`.`ID_vente`union all select coalesce(`ver`.`type_versement`,'achat') AS `nature`,`a`.`entrepot_id` AS `entrepot`,`a`.`code_achat` AS `code_transaction`,`ver`.`pay_mode` AS `pay_mode`,`a`.`created_at` AS `date_facture`,`a`.`statut_achat` AS `statut_commande`,`vma`.`montant_total` AS `montant_facture`,coalesce(sum(`ver`.`montant_versement`),0) AS `total_paye`,(`vma`.`montant_total` - coalesce(sum(`ver`.`montant_versement`),0)) AS `reste_a_payer`,(case when (coalesce(sum(`ver`.`montant_versement`),0) <= 0) then 'Non payé' when (coalesce(sum(`ver`.`montant_versement`),0) < `vma`.`montant_total`) then 'Partiel' else 'Soldé' end) AS `statut_paiement` from (((`achat` `a` join `vue_montant_achats` `vma` on((`vma`.`code_achat` = `a`.`code_achat`))) join `entree` `en` on((`en`.`achat_id` = `a`.`code_achat`))) left join `versement` `ver` on(((`a`.`code_achat` = `ver`.`transaction_code`) and (`ver`.`type_versement` = 'achat') and (`ver`.`etat_versement` = 1)))) where (`a`.`statut_achat` in ('valide','encaisse')) group by `a`.`ID_achat`  ;

CREATE  VIEW `vue_dernier_inventaire_entrepot`  AS SELECT `st`.`article_id` AS `article_id`, `st`.`entrepot_id` AS `entrepot_id`, max(`st`.`ID_mouvement_stock`) AS `last_inv_id`, `st`.`quantite` AS `quantite_inv`, `st`.`prix_achat` AS `prix_achat`, `st`.`prix_vente` AS `prix_vente`, `st`.`date_mouvement` AS `date_inventaire` FROM `mouvement_stock` AS `st` WHERE (`st`.`type_mouvement` = 'INVENTAIRE') GROUP BY `st`.`article_id`, `st`.`entrepot_id`, `st`.`quantite` ;

CREATE  VIEW `vue_caisse_mode_paiement`  AS SELECT `t`.`entrepot_id` AS `entrepot_id`, `t`.`mode_paiement` AS `mode_paiement`, sum(`t`.`entree`) AS `total_entree`, sum(`t`.`sortie_achat`) AS `total_sortie_achat`, sum(`t`.`depense`) AS `total_depense`, ((sum(`t`.`entree`) - sum(`t`.`sortie_achat`)) - sum(`t`.`depense`)) AS `solde` FROM (select `ve`.`entrepot_id` AS `entrepot_id`,coalesce(`v`.`pay_mode`,'inconnu') AS `mode_paiement`,`v`.`montant_versement` AS `entree`,0 AS `sortie_achat`,0 AS `depense` from (`versement` `v` join `vente` `ve` on((`ve`.`code_vente` = `v`.`transaction_code`))) where ((`v`.`type_versement` = 'vente') and (`v`.`etat_versement` = 1)) union all select `ac`.`entrepot_id` AS `entrepot_id`,coalesce(`v`.`pay_mode`,'inconnu') AS `COALESCE(v.pay_mode, 'inconnu')`,0 AS `0`,`v`.`montant_versement` AS `montant_versement`,0 AS `0` from (`versement` `v` join `achat` `ac` on((`ac`.`code_achat` = `v`.`transaction_code`))) where ((`v`.`type_versement` = 'achat') and (`v`.`etat_versement` = 1)) union all select `d`.`entrepot_id` AS `entrepot_id`,'especes' AS `mode_paiement`,0 AS `0`,0 AS `0`,`d`.`montant` AS `montant` from `depense` `d` where (`d`.`etat_depense` = 0)) AS `t` GROUP BY `t`.`entrepot_id`, `t`.`mode_paiement` ;





CREATE  VIEW `vue_flux_post_inventaire`  AS SELECT `m`.`article_id` AS `article_id`, `m`.`entrepot_id` AS `entrepot_id`, sum((case when (`m`.`type_mouvement` in ('ENTREE','RETOUR_CLIENT','TRANSFERT_IN','AJUSTEMENT_POSITIF')) then `m`.`quantite` when (`m`.`type_mouvement` in ('SORTIE','RETOUR_FOURNISSEUR','TRANSFERT_OUT','AJUSTEMENT_NEGATIF')) then -(`m`.`quantite`) else 0 end)) AS `total_flux` FROM (`mouvement_stock` `m` join `vue_dernier_inventaire_entrepot` `vdi` on(((`m`.`article_id` = `vdi`.`article_id`) and (`m`.`entrepot_id` = `vdi`.`entrepot_id`)))) WHERE (`m`.`ID_mouvement_stock` > `vdi`.`last_inv_id`) GROUP BY `m`.`article_id`, `m`.`entrepot_id` ;

CREATE  VIEW `vue_stock_produit`  AS SELECT `a`.`ID_article` AS `article_id`, `a`.`libelle_article` AS `libelle_article`, `e`.`ID_entrepot` AS `entrepot_id`, `e`.`libelle_entrepot` AS `libelle_entrepot`, (coalesce(`vdi`.`quantite_inv`,0) + coalesce(`vfp`.`total_flux`,0)) AS `quantite_disponible`, ((coalesce(`vdi`.`quantite_inv`,0) + coalesce(`vfp`.`total_flux`,0)) * (select `mouvement_stock`.`prix_achat` from `mouvement_stock` where ((`mouvement_stock`.`article_id` = `a`.`ID_article`) and (`mouvement_stock`.`prix_achat` > 0)) order by `mouvement_stock`.`date_mouvement` desc,`mouvement_stock`.`ID_mouvement_stock` desc limit 1)) AS `montant_total_stock` FROM ((((`article` `a` join `entrepot_article` `ea` on((`a`.`ID_article` = `ea`.`article_id`))) join `entrepot` `e` on((`e`.`ID_entrepot` = `ea`.`entrepot_id`))) left join `vue_dernier_inventaire_entrepot` `vdi` on(((`a`.`ID_article` = `vdi`.`article_id`) and (`e`.`ID_entrepot` = `vdi`.`entrepot_id`)))) left join `vue_flux_post_inventaire` `vfp` on(((`a`.`ID_article` = `vfp`.`article_id`) and (`e`.`ID_entrepot` = `vfp`.`entrepot_id`)))) ;

CREATE  VIEW `vue_bilan_articles`  AS SELECT `ea`.`entrepot_id` AS `entrepot_id`, `e`.`libelle_entrepot` AS `libelle_entrepot`, `a`.`ID_article` AS `article_id`, `a`.`libelle_article` AS `libelle_article`, (coalesce(`vdi`.`quantite_inv`,0) + coalesce((select sum((case when (`m`.`type_mouvement` in ('ENTREE','TRANSFERT_IN','AJUSTEMENT_POSITIF')) then `m`.`quantite` when (`m`.`type_mouvement` = 'RETOUR_FOURNISSEUR') then -(`m`.`quantite`) else 0 end)) from `mouvement_stock` `m` where ((`m`.`article_id` = `a`.`ID_article`) and (`m`.`entrepot_id` = `ea`.`entrepot_id`) and (`m`.`ID_mouvement_stock` > `vdi`.`last_inv_id`))),0)) AS `qte_approvisionnement`, (coalesce((`vdi`.`quantite_inv` * `ea`.`prix_achat`),0) + coalesce((select sum((case when (`m`.`type_mouvement` in ('ENTREE','TRANSFERT_IN','AJUSTEMENT_POSITIF')) then (`m`.`quantite` * `ea`.`prix_achat`) when (`m`.`type_mouvement` = 'RETOUR_FOURNISSEUR') then -((`m`.`quantite` * `ea`.`prix_achat`)) else 0 end)) from `mouvement_stock` `m` where ((`m`.`article_id` = `a`.`ID_article`) and (`m`.`entrepot_id` = `ea`.`entrepot_id`) and (`m`.`ID_mouvement_stock` > `vdi`.`last_inv_id`))),0)) AS `cout_achat`, coalesce((select sum((case when (`m`.`type_mouvement` = 'SORTIE') then `m`.`quantite` when (`m`.`type_mouvement` = 'RETOUR_CLIENT') then -(`m`.`quantite`) else 0 end)) from `mouvement_stock` `m` where ((`m`.`article_id` = `a`.`ID_article`) and (`m`.`entrepot_id` = `ea`.`entrepot_id`) and (`m`.`ID_mouvement_stock` > `vdi`.`last_inv_id`))),0) AS `qte_vendue`, coalesce((select sum((case when (`m`.`type_mouvement` = 'SORTIE') then (`m`.`quantite` * `m`.`prix_vente`) when (`m`.`type_mouvement` = 'RETOUR_CLIENT') then -((`m`.`quantite` * `m`.`prix_vente`)) else 0 end)) from `mouvement_stock` `m` where ((`m`.`article_id` = `a`.`ID_article`) and (`m`.`entrepot_id` = `ea`.`entrepot_id`) and (`m`.`ID_mouvement_stock` > `vdi`.`last_inv_id`))),0) AS `montant_vendu`, coalesce((select sum((case when (`m`.`type_mouvement` = 'SORTIE') then (`m`.`quantite` * (`m`.`prix_vente` - `ea`.`prix_achat`)) when (`m`.`type_mouvement` = 'RETOUR_CLIENT') then -((`m`.`quantite` * (`m`.`prix_vente` - `ea`.`prix_achat`))) else 0 end)) from `mouvement_stock` `m` where ((`m`.`article_id` = `a`.`ID_article`) and (`m`.`entrepot_id` = `ea`.`entrepot_id`) and (`m`.`ID_mouvement_stock` > `vdi`.`last_inv_id`))),0) AS `benefice`, coalesce(`vs`.`quantite_disponible`,0) AS `qte_restante`, (coalesce(`vs`.`quantite_disponible`,0) * `ea`.`prix_achat`) AS `montant_quantite_restant` FROM ((((`entrepot_article` `ea` join `article` `a` on((`ea`.`article_id` = `a`.`ID_article`))) join `entrepot` `e` on((`ea`.`entrepot_id` = `e`.`ID_entrepot`))) left join `vue_dernier_inventaire_entrepot` `vdi` on(((`a`.`ID_article` = `vdi`.`article_id`) and (`e`.`ID_entrepot` = `vdi`.`entrepot_id`)))) left join `vue_stock_produit` `vs` on(((`a`.`ID_article` = `vs`.`article_id`) and (`e`.`ID_entrepot` = `vs`.`entrepot_id`)))) ORDER BY `e`.`libelle_entrepot` ASC, `a`.`libelle_article` ASC ;